Span<nuint> unsignedSpan = stackalloc nuint[4];
for (int i = 0; i < unsignedSpan.Length; i++) unsignedSpan[i] = (nuint)(i * 20);

Console.WriteLine("Span<nint>:");
for (int i = 0; i < signedSpan.Length; i++) Console.WriteLine($"  [{i}] = {signedSpan[i]}");

Console.WriteLine("Span<nuint>:");
for (int i = 0; i < unsignedSpan.Length; i++) Console.WriteLine($"  [{i}] = {unsignedSpan[i]}");

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");
EOF
